import { Background } from '../backgrounds';

export const scene: DialogueEntry[] = [
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "18:05。清澄區民館。三樓。", background: Background.Chapter_11_Ch11_Act2_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "澪站在走廊盡頭。電梯出來左轉，走到底。走廊很普通。日光燈。塑膠地板。佈告欄上貼著書法班招生、育兒相談預約、町內會防災講習、老人手機教室的公告。每一張都褪了色。每一張都像在這裡貼了很久。", background: Background.Chapter_11_Ch11_Act2_S0 },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "（內心）⋯⋯就是這裡。普通到不能再普通。沒有任何東西讓你覺得這棟樓裡正在發生不普通的事。", background: Background.Chapter_11_Ch11_Act2_S0, portrait: Portrait.AsakuraMio_Determined },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "手機震了一下。琴音。", background: Background.Chapter_11_Ch11_Act2_S0 },
    { characterId: CharacterId.Message, character: "訊息", dialogue: "醒了回我。我把吃的放冰箱。", background: Background.Chapter_11_Ch11_Act2_S0 },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "（內心）⋯⋯⋯⋯", background: Background.Chapter_11_Ch11_Act2_S0, portrait: Portrait.AsakuraMio_Sad },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "她看著那行字。很普通的關心。像每一天都會收到的那種。", background: Background.Chapter_11_Ch11_Act2_S0 },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "我會晚點回。", background: Background.Chapter_11_Ch11_Act2_S0, portrait: Portrait.AsakuraMio_Determined },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "五個字。她沒有說去哪裡。沒有說幾點。沒有說和誰。", background: Background.Chapter_11_Ch11_Act2_S0 },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "（內心）⋯⋯這不是隱瞞。這只是不說。不說和隱瞞之間有一條線。我現在站在線上。", background: Background.Chapter_11_Ch11_Act2_S0, portrait: Portrait.AsakuraMio_Sad },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "她把手機收進口袋。往前走了幾步。", background: Background.Chapter_11_Ch11_Act2_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "走廊中段。一扇門半開著。門上貼了一張 A4 紙。白紙。黑字。列印的。沒有 logo。沒有插圖。沒有顏色。", background: Background.Chapter_11_Ch11_Act2_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "紙上寫著：", background: Background.Chapter_11_Ch11_Act2_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "失蹤青少年家屬資料整理會。", background: Background.Chapter_11_Ch11_Act2_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "下面一行小字：請勿攝影／請使用影本。", background: Background.Chapter_11_Ch11_Act2_S0 },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "（內心）⋯⋯沒有別的了。沒有第七曙光。沒有倒月。沒有七條線。沒有黑色海。沒有任何讓外人一眼就能辨識的東西。就一張白紙。黑字。像區民館裡任何一個臨時借用會議室的公告。", background: Background.Chapter_11_Ch11_Act2_S0, portrait: Portrait.AsakuraMio_Determined },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "她站在門前。沒有進去。", background: Background.Chapter_11_Ch11_Act2_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "門開了。水瀨佳乃從裡面走出來。她看到澪，點了一下頭。沒有笑。也沒有客套。", background: Background.Chapter_11_Ch11_Act2_S0 },
    { characterId: CharacterId.MinaseYoshino, character: "水瀨佳乃", dialogue: "我帶妳來，不代表裡面的人會相信妳。", background: Background.Chapter_11_Ch11_Act2_S0, portrait: Portrait.MinaseYoshino_Guarded },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "（內心）⋯⋯我知道。", background: Background.Chapter_11_Ch11_Act2_S0, portrait: Portrait.AsakuraMio_Determined },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "水瀨佳乃沒有等她回答。她轉身，走進門裡。澪跟在後面。", background: Background.Chapter_11_Ch11_Act2_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "會議室不大。折疊桌排成不規則的長方形。椅子十來張。金屬腳。坐墊很薄。", background: Background.Chapter_11_Ch11_Act2_S1 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "桌角有一個紙箱。箱子裡有幾個編號的不透明拉鍊袋。", background: Background.Chapter_11_Ch11_Act2_S1 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "水瀨佳乃站在門邊。她指了一下那個箱子。", background: Background.Chapter_11_Ch11_Act2_S1 },
    { characterId: CharacterId.MinaseYoshino, character: "水瀨佳乃", dialogue: "手機。先關掉通知預覽，開飛航模式。然後自己放進袋子，自己封口。散場的時候憑編號拿回。", background: Background.Chapter_11_Ch11_Act2_S1, portrait: Portrait.MinaseYoshino_Guarded },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "（內心）⋯⋯⋯⋯為什麼？", background: Background.Chapter_11_Ch11_Act2_S1, portrait: Portrait.AsakuraMio_Determined },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "她沒有問出口。但水瀨佳乃好像讀到了。", background: Background.Chapter_11_Ch11_Act2_S1 },
    { characterId: CharacterId.MinaseYoshino, character: "水瀨佳乃", dialogue: "有人把孩子夢話剪成怪談影片。有人假扮家屬進來套話。自媒體、網友、記者，什麼人都有。", background: Background.Chapter_11_Ch11_Act2_S1, portrait: Portrait.MinaseYoshino_Guarded },
    { characterId: CharacterId.MinaseYoshino, character: "水瀨佳乃", dialogue: "我們不是在搞神祕。我們是被嚇怕了。", background: Background.Chapter_11_Ch11_Act2_S1, portrait: Portrait.MinaseYoshino_Guarded },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "（內心）⋯⋯⋯⋯", background: Background.Chapter_11_Ch11_Act2_S1, portrait: Portrait.AsakuraMio_Determined },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "澪看了一眼房間裡的人。八個。也許九個。有男有女。年紀不同。有人在吃便利店飯糰。有人膝上攤著一張紙本排班表，手指在格子裡移動，像在算明早能不能準時上班。有人還穿著反光工作背心。", background: Background.Chapter_11_Ch11_Act2_S1 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "不是教徒。不是情報人員。是一群下班後趕過來的人。", background: Background.Chapter_11_Ch11_Act2_S1 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "門邊有一張簽到紙。水瀨佳乃指了一下。", background: Background.Chapter_11_Ch11_Act2_S1 },
    { characterId: CharacterId.MinaseYoshino, character: "水瀨佳乃", dialogue: "不要寫全名。寫代號，還有失蹤或昏迷的天數。", background: Background.Chapter_11_Ch11_Act2_S1, portrait: Portrait.MinaseYoshino_Guarded },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "澪拿起筆。她寫了「姐姐」。後面寫「9」。", background: Background.Chapter_11_Ch11_Act2_S1 },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "（內心）⋯⋯九日。悠真失蹤第九日。", background: Background.Chapter_11_Ch11_Act2_S1, portrait: Portrait.AsakuraMio_Determined },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "她放下筆。水瀨佳乃又說了幾條規則。語氣像在讀已經重複過很多次的清單。", background: Background.Chapter_11_Ch11_Act2_S1 },
    { characterId: CharacterId.MinaseYoshino, character: "水瀨佳乃", dialogue: "不帶原件。不錄音。不拍照。不把其他家庭的資料帶出這個房間。", background: Background.Chapter_11_Ch11_Act2_S1, portrait: Portrait.MinaseYoshino_Guarded },
    { characterId: CharacterId.MinaseYoshino, character: "水瀨佳乃", dialogue: "新來的人，先說自己已經看過哪些案例資料。", background: Background.Chapter_11_Ch11_Act2_S1, portrait: Portrait.MinaseYoshino_Guarded },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "（內心）⋯⋯先說已經看過什麼。不是先問我弟弟畫了什麼。是先問我已經被污染了多少。", background: Background.Chapter_11_Ch11_Act2_S1, portrait: Portrait.AsakuraMio_Determined },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "她明白了。這不是偏執。這是防污染。", background: Background.Chapter_11_Ch11_Act2_S1 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "門邊有人正在匆忙地按手機。螢幕亮著。手指很快。像在回最後一則工作訊息。回完之後他把螢幕按滅，關掉通知預覽，調成飛航模式，拿起一個編號袋，把手機放進去，拉上封口。動作很熟練。像做過很多次。", background: Background.Chapter_11_Ch11_Act2_S1 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "袋子放進紙箱。箱子在桌角。所有人都看得見。", background: Background.Chapter_11_Ch11_Act2_S1 },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "（內心）⋯⋯封口之後，桌上就不會再出現私人手機了。所有人都在同一個狀態。沒有人能偷拍。沒有人能偷傳。沒有人比別人多一條對外的線。", background: Background.Chapter_11_Ch11_Act2_S1, portrait: Portrait.AsakuraMio_Determined },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "澪拿出自己的手機。她先看了一眼。", background: Background.Chapter_11_Ch11_Act2_S1 },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "（內心）⋯⋯琴音沒有新回覆。「我會晚點回。」她沒有再追問。", background: Background.Chapter_11_Ch11_Act2_S1, portrait: Portrait.AsakuraMio_Determined },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "她關掉通知預覽。飛航模式。拿起一個編號袋。數字是 7。", background: Background.Chapter_11_Ch11_Act2_S1 },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "（內心）⋯⋯7。", background: Background.Chapter_11_Ch11_Act2_S1, portrait: Portrait.AsakuraMio_Shocked },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "她頓了一下。然後把手機放進去。拉上封口。放進紙箱。", background: Background.Chapter_11_Ch11_Act2_S1 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "口袋空了。手機不在身上了。那種輕的感覺很陌生。像少了一層皮。", background: Background.Chapter_11_Ch11_Act2_S1 },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "（內心）⋯⋯好了。現在我和這個房間裡所有人一樣。沒有對外的線。只有自己帶來的東西。", background: Background.Chapter_11_Ch11_Act2_S1, portrait: Portrait.AsakuraMio_Determined },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "她抬頭。會議室的燈是正常亮度。投影幕空白。桌面上的資料夾封面朝下。", background: Background.Chapter_11_Ch11_Act2_S1 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "沒有任何符號。沒有任何圖案。沒有任何讓她覺得自己走進了什麼不普通的東西。", background: Background.Chapter_11_Ch11_Act2_S1 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "只有一個普通的房間。一群普通的人。和一張寫著「失蹤青少年家屬資料整理會」的白紙。", background: Background.Chapter_11_Ch11_Act2_S1 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "水瀨佳乃站在她旁邊。沒有再說話。只是等著。", background: Background.Chapter_11_Ch11_Act2_S1 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "等她準備好。", background: Background.Chapter_11_Ch11_Act2_S1 },
];
